import{_ as a,o as i,c as t,a2 as l}from"./chunks/framework.OWFDNrRT.js";const p=JSON.parse('{"title":"ADR-007: Observability as First-Class Feature","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-007-observability-first.md","filePath":"adr/ADR-007-observability-first.md","lastUpdated":1773460793000}'),s={name:"adr/ADR-007-observability-first.md"};function r(o,e,n,d,c,u){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="adr-007-observability-as-first-class-feature" tabindex="-1">ADR-007: Observability as First-Class Feature <a class="header-anchor" href="#adr-007-observability-as-first-class-feature" aria-label="Permalink to &quot;ADR-007: Observability as First-Class Feature&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-09 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Since no human inspects code, the framework must expose truth through tools. If agents can&#39;t see the system clearly, they will thrash. This is non-negotiable for agent-driven development.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>DINOForge requires comprehensive observability at every layer.</p><h3 id="runtime-logs" tabindex="-1">Runtime Logs <a class="header-anchor" href="#runtime-logs" aria-label="Permalink to &quot;Runtime Logs&quot;">​</a></h3><ul><li>What loaded, what failed</li><li>What got patched</li><li>Missing references</li><li>Fallback activations</li><li>Version mismatches</li><li>Performance warnings</li></ul><h3 id="in-game-debug-overlay" tabindex="-1">In-Game Debug Overlay <a class="header-anchor" href="#in-game-debug-overlay" aria-label="Permalink to &quot;In-Game Debug Overlay&quot;">​</a></h3><ul><li>Loaded packs</li><li>Active faction definitions</li><li>Entity counts</li><li>Unit mappings</li><li>Wave composition preview</li><li>Missing asset markers</li><li>Component values</li><li>Spawn diagnostics</li></ul><h3 id="dump-tools" tabindex="-1">Dump Tools <a class="header-anchor" href="#dump-tools" aria-label="Permalink to &quot;Dump Tools&quot;">​</a></h3><ul><li>Entity/component dump</li><li>Prefab mapping dump</li><li>Localization table dump</li><li>Research tree dump</li><li>Wave table dump</li></ul><h3 id="validation-reports" tabindex="-1">Validation Reports <a class="header-anchor" href="#validation-reports" aria-label="Permalink to &quot;Validation Reports&quot;">​</a></h3><ul><li>Pack validity</li><li>Unresolved references</li><li>Duplicate IDs</li><li>Incompatible overrides</li><li>Asset holes</li><li>Unsupported game version</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Every registry operation is logged</li><li>Every pack load emits a structured report</li><li>Every validation failure is machine-parseable</li><li>Debug overlay can be toggled at runtime</li><li>Dump tools can be invoked by agents to understand game state</li><li>Agents can diagnose failures without reading source code</li></ul>',16)])])}const m=a(s,[["render",r]]);export{p as __pageData,m as default};
